    fun chatCompletionsUrl(): String = baseUrl.trimEnd('/').let {
        if (it.endsWith("/chat/completions")) it else "$it/chat/completions"
    }

    private fun validateEndpoint(value: String, allowCleartext: Boolean): String? = runCatching {
