            require(uri.scheme != "http" || allowCleartext) { "鏈満 HTTP 鏈嶅姟闇€鏄惧紡鍏佽鏄庢枃杩炴帴" }
        }
    }.exceptionOrNull()?.message
}

data class LunaChatMessage(val role: String, val content: String)

class LunaChatClient(
    private val config: LunaChatConfig,
    private val gson: Gson = Gson(),
) {
    fun reply(history: List<LunaChatMessage>): Result<String> = runCatching {
        config.validationError?.let { throw LunaChatException(it) }
        val connection = (URL(config.chatCompletionsUrl()).openConnection() as HttpURLConnection).apply {
            requestMethod = "POST"
            connectTimeout = CONNECT_TIMEOUT_MILLIS
            readTimeout = READ_TIMEOUT_MILLIS
            doOutput = true
            setRequestProperty("Content-Type", "application/json; charset=utf-8")
            setRequestProperty("Accept", "application/json")
        }
        try {
            val payload = ChatCompletionsRequest(model = config.model, messages = history)
            OutputStreamWriter(connection.outputStream, StandardCharsets.UTF_8).use { writer ->
                writer.write(gson.toJson(payload))
            }
            if (connection.responseCode !in 200..299) {
                throw LunaChatException("鏈満 AI 鏈嶅姟鏈帴鍙楄姹傦紙HTTP ${connection.responseCode}锛?)
            }
            val response = connection.inputStream.bufferedReader(StandardCharsets.UTF_8).use(BufferedReader::readText)
            parseAssistantReply(response)
        } catch (exception: LunaChatException) {
            throw exception
        } catch (exception: Exception) {
            throw LunaChatException("鏃犳硶杩炴帴鏈満 AI 鏈嶅姟锛岃纭鍦板潃涓庢湇鍔＄姸鎬?, exception)
        } finally {
            connection.disconnect()
        }
    }

    internal fun parseAssistantReply(response: String): String {
        val content = JsonParser.parseString(response)
            .asJsonObject
            .getAsJsonArray("choices")
            ?.firstOrNull()
            ?.asJsonObject
            ?.getAsJsonObject("message")
            ?.get("content")
            ?.takeIf { it.isJsonPrimitive }
            ?.asString
            ?.trim()
            .orEmpty()
        if (content.isBlank()) throw LunaChatException("鏈満 AI 鏈嶅姟鏈繑鍥炲彲鏄剧ず鐨勫洖绛?)
        return content
    }

    private data class ChatCompletionsRequest(
        val model: String,
        val messages: List<LunaChatMessage>,
        val temperature: Double = 0.3,
    )

    private companion object {
        const val CONNECT_TIMEOUT_MILLIS = 10_000
        const val READ_TIMEOUT_MILLIS = 30_000
    }
}

class LunaChatException(message: String, cause: Throwable? = null) : RuntimeException(message, cause)

package com.rehealth.genie.chat

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.rehealth.genie.BuildConfig
import kotlinx.coroutines.Dispatchers
