package com.rehealth.genie.chat

import org.junit.Assert.assertEquals
import org.junit.Assert.assertNull
import org.junit.Assert.assertTrue
import org.junit.Test

class LunaChatClientTest {
    @Test
    fun `configured https endpoint creates chat completions path`() {
        val config = LunaChatConfig(
            baseUrl = "https://ai.example.test/v1",
            model = "gpt-5.6-luna",
            enabled = true,
            allowCleartext = false,
        )

        assertNull(config.validationError)
        assertEquals("https://ai.example.test/v1/chat/completions", config.chatCompletionsUrl())
        assertEquals("ai.example.test", config.endpointLabel)
    }

    @Test
    fun `http endpoint needs explicit cleartext opt in`() {
        val config = LunaChatConfig(
            baseUrl = "http://192.168.1.6:8000/v1",
            model = "gpt-5.6-luna",
            enabled = true,
            allowCleartext = false,
        )

        assertTrue(config.validationError.orEmpty().contains("鏄惧紡鍏佽鏄庢枃"))
    }

    @Test
    fun `parses OpenAI compatible assistant content`() {
        val client = LunaChatClient(
            LunaChatConfig("https://ai.example.test/v1", "gpt-5.6-luna", true, false),
        )

        assertEquals("鎮ㄥソ", client.parseAssistantReply("{\"choices\":[{\"message\":{\"content\":\" 鎮ㄥソ \"}}]}"))
    }
}

