@Composable
private fun DataScreen(
    state: RingUiState,
    onMeasure: (RingMetricType) -> Unit,
    onMetricDetail: (RingMetricType) -> Unit,
    onShowCvd16: () -> Unit,
) {
    var selectedPeriod by remember { mutableIntStateOf(1) }
    val periodDays = listOf(1L, 7L, 30L, 90L)[selectedPeriod]
    val since = System.currentTimeMillis() - periodDays * 24 * 60 * 60 * 1000

    fun measurement(type: RingMetricType): String {
        val record = state.measurements[type] ?: return "--"
        if (!isCurrentMrdMeasurement(record.measuredAt, record.source, state.connectedDevice != null)) return "--"
        return if (type == RingMetricType.BLOOD_PRESSURE) {
            "${record.primaryValue.toInt()}/${record.secondaryValue?.toInt() ?: "--"}"
        } else if (type == RingMetricType.TEMPERATURE) {
            String.format(Locale.getDefault(), "%.1f", record.primaryValue)
        } else {
            record.primaryValue.toInt().toString()
        }
    }
    val sleepMinutes = state.sleep?.let { (it.endedAt - it.startedAt) / 60_000 }
    val sleepValue = sleepMinutes?.let { "${it / 60}h${it % 60}m" } ?: "--"
    val vitalMetrics = listOf(
        RingMetricUi(RingMetricType.HEART_RATE, "心率", measurement(RingMetricType.HEART_RATE), "bpm", liveStatus(state, RingMetricType.HEART_RATE), Icons.Outlined.FavoriteBorder, Color(0xFFFF6078), manualMeasure = true),
        RingMetricUi(RingMetricType.HRV, "HRV", measurement(RingMetricType.HRV), "ms", liveStatus(state, RingMetricType.HRV), Icons.Outlined.Timeline, Color(0xFF2DA8A0), manualMeasure = true),
        RingMetricUi(RingMetricType.BLOOD_OXYGEN, "血氧", measurement(RingMetricType.BLOOD_OXYGEN), "%", liveStatus(state, RingMetricType.BLOOD_OXYGEN), Icons.Outlined.DataUsage, Color(0xFF148BFF), manualMeasure = true),
        RingMetricUi(RingMetricType.BLOOD_PRESSURE, "血压", measurement(RingMetricType.BLOOD_PRESSURE), "mmHg", liveStatus(state, RingMetricType.BLOOD_PRESSURE), Icons.Outlined.FavoriteBorder, Color(0xFF8B63F6), manualMeasure = true),
        RingMetricUi(RingMetricType.TEMPERATURE, "体温", measurement(RingMetricType.TEMPERATURE), "°C", liveStatus(state, RingMetricType.TEMPERATURE), Icons.Outlined.Assessment, Color(0xFFFF8A32), manualMeasure = true, actionLabel = "开启", measuringLabel = "采集中"),
    )
    val sleepHistory = state.sleepHistory.filter { it.endedAt >= since }
    val activityHistory = state.activityHistory.filter { it.startedAt >= since }
    val averageSleepMinutes = sleepHistory.map { it.deepMinutes + it.lightMinutes + it.remMinutes }.average().takeIf { !it.isNaN() }
    val averageSteps = state.measurementHistory[RingMetricType.STEPS].orEmpty()
        .filter { it.measuredAt >= since }.map { it.primaryValue }.average().takeIf { !it.isNaN() }
    val sleepPoints = sleepHistory.map { (it.deepMinutes + it.lightMinutes + it.remMinutes).toDouble() }.toChartPoints()
    val stepPoints = state.measurementHistory[RingMetricType.STEPS].orEmpty()
        .filter { it.measuredAt >= since }.map { it.primaryValue }.toChartPoints()
    val dailyMetrics = listOf(
        RingMetricUi(RingMetricType.SLEEP, "睡眠", averageSleepMinutes?.toDurationLabel() ?: sleepValue, "", if (averageSleepMinutes == null) "暂无真实数据" else "${periodDays} 天平均", Icons.Outlined.AutoAwesome, Color(0xFF9668EF), chartPoints = sleepPoints),
        RingMetricUi(RingMetricType.STEPS, "步数", averageSteps?.toInt()?.toString() ?: measurement(RingMetricType.STEPS), "步", if (averageSteps == null) "暂无真实数据" else "${periodDays} 天平均", Icons.Outlined.ShowChart, Color(0xFF20B77A), chartPoints = stepPoints),
    )

    LazyColumn(
        modifier = Modifier.fillMaxSize().background(
            Brush.radialGradient(
                colors = listOf(Color(0xFFE9FBF6), Canvas),
                radius = 900f,
            ),
        ),
        contentPadding = androidx.compose.foundation.layout.PaddingValues(
            start = 16.dp,
            top = 32.dp,
            end = 16.dp,
            bottom = 12.dp,
        ),
        verticalArrangement = Arrangement.spacedBy(11.dp),
    ) {
        item {
            Row(verticalAlignment = Alignment.CenterVertically) {
                Column(Modifier.weight(1f)) {
                    Text("健康数据", color = Ink, fontSize = 24.sp, fontWeight = FontWeight.Bold)
                    Text("近 ${periodDays} 天本机戒指数据", color = Muted, fontSize = 12.sp, modifier = Modifier.padding(top = 3.dp))
                }
                Box(
                    modifier = Modifier.size(38.dp).clip(CircleShape)
                        .border(1.dp, Ink, CircleShape),
                    contentAlignment = Alignment.Center,
                ) {
                    Icon(Icons.Outlined.Assessment, "数据概览", tint = Ink, modifier = Modifier.size(20.dp))
                }
            }
        }
        item {
            PeriodSelector(
                labels = listOf("今日", "7 天", "30 天", "90 天"),
                selected = selectedPeriod,
                onSelected = { selectedPeriod = it },
            )
        }
        if (state.message != null || state.isSyncing) {
            item {
                DataStatusCard(state)
            }
        }
        item {
            Row(
                modifier = Modifier.fillMaxWidth().height(178.dp),
                horizontalArrangement = Arrangement.spacedBy(12.dp),
            ) {
                HealthScoreCard(Modifier.weight(1f), onShowCvd16)
                SmartRingOverviewCard(state, Modifier.weight(1f))
            }
        }
        item {
            DashboardSectionHeader(Icons.Outlined.FavoriteBorder, "生命体征") { onMetricDetail(RingMetricType.HEART_RATE) }
        }
        item {
            MetricGrid(
                metrics = vitalMetrics,
                measuringMetric = state.measuringMetric,
                onMeasure = onMeasure,
                measureEnabled = !state.isSyncing,
                onMetricDetail = onMetricDetail,
            )
        }
        item {
            DashboardSectionHeader(Icons.Outlined.Timeline, "睡眠与活动") { onMetricDetail(RingMetricType.SLEEP) }
        }
        item {
            MetricGrid(dailyMetrics, onMetricDetail = onMetricDetail)
        }
        item {
            Row(
                modifier = Modifier.fillMaxWidth().clip(RoundedCornerShape(18.dp))
                    .background(Brush.horizontalGradient(listOf(Color(0xFFF4FFFB), Color(0xFFE3F9F2))))
                    .border(1.dp, Color(0xFFCDEBE2), RoundedCornerShape(18.dp))

